#include <cmath>
#include <iostream>

int main() {
    // متجهان ثنائيان الأبعاد
    double ax = 1.0, ay = 0.0;
    double bx = 1.0, by = 1.0;

    // حاصل الضرب النقطي
    double dot = ax * bx + ay * by;
    // طول كل متجه
    double len_a = std::sqrt(ax * ax + ay * ay);
    double len_b = std::sqrt(bx * bx + by * by);

    // الزاوية بينهما
    double cos_angle = dot / (len_a * len_b);
    double angle = std::acos(cos_angle);
    std::cout << angle << " radians"; // π/4 (45°)
}

