#include <cmath>

struct Vec3 { double x, y, z; };

Vec3 normalize(Vec3 v) {
    double len = std::sqrt(v.x * v.x + v.y * v.y + v.z * v.z);
    if (std::isnan(len) || len == 0.0) {
        return {0, 0, 0};
    }
    return {v.x / len, v.y / len, v.z / len};
}

