#include <numeric>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4};
    std::vector<int> excl(v.size()), incl(v.size()), ps(v.size());

    std::exclusive_scan(v.begin(), v.end(), excl.begin(), 0);
    std::inclusive_scan(v.begin(), v.end(), incl.begin());
    std::partial_sum(v.begin(), v.end(), ps.begin());

    for (int x : excl) std::cout << x << ' '; // 0 1 3 6
    std::cout << '\n';
    for (int x : incl) std::cout << x << ' '; // 1 3 6 10
    std::cout << '\n';
    for (int x : ps) std::cout << x << ' ';   // 1 3 6 10
    // inclusive_scan == partial_sum
}

