#include <cmath>
#include <iostream>

int main() {
    double x = 5.0;
    // الطريقة المباشرة: log(tgamma(x)) — قد تتجاوز لقيم كبيرة
    double direct = std::log(std::tgamma(x)); // log(24) ≈ 3.178

    // الطريقة الآمنة: lgamma(x) — لا تتجاوز أبدًا
    double safe = std::lgamma(x);               // ≈ 3.178

    std::cout << direct << ' ' << safe; // نفس النتيجة لقيم صغيرة

    // مع x = 200: tgamma(200) قد تتجاوز لكن lgamma(200) آمنة
    double big = std::lgamma(200.0); // ≈ 857.933
}

#include <cmath>
#include <iostream>

int main() {
    // lgamma(x) = ln(|Γ(x)|) — يأخذ القيمة المطلقة
    // هذا يعني أنه يعمل حتى عندما تكون Γ(x) سالبة
    // (Γ سالبة لبعض القيم العشرية بين 0 و1)

    double r = std::lgamma(0.5); // ln(√π) ≈ 0.572
    std::cout << r << '\n';

    // معامل اختياري: signptr للحصول على إشارة Γ(x)
    int sign = 0;
    double r2 = std::lgamma(0.5, &sign);
    std::cout << "value: " << r2 << ", sign: " << sign << '\n';
    // sign = 1 (Γ(0.5) موجبة)
}

